insert into public.content (id, kind, slug, title, body, phase, lang, photo_paths, status, updated_at) values
  (gen_random_uuid(), 'manual', 'manual-welcome', 'はじめに', 'KRAFT BASE は熊野古道・小口のゲストハウス。「Unplug to recharge.」歩く人が静かに整う場所として迎える。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'manual', 'manual-facility', '施設・設備・館内ルール', 'ドミトリー、和室、共用キッチン、無料の洗濯機・乾燥機、Wi-Fi、屋外喫煙所。21:00以降は静かに。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'manual', 'manual-mindset', '接客の基本姿勢', '勝手に足さない。まず運営に提案。引き算で、取りこぼさず、押し付けない。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'manual', 'manual-checkout', '朝：チェックアウト対応', 'コーヒーとバナナを案内。翌朝のバスを前夜に伝える。お礼/レビュー依頼は予約サイト経由（対面では依頼しない）。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'manual', 'manual-midday', '日中：清掃・洗濯・準備', '清掃・洗濯・ベッドメイク・補充。受付準備を15:00までに整える。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'manual', 'manual-afternoon', '午後：チェックイン業務', '名前確認、パスポート確認（法定）、ベッド案内、館内案内。ウェルカムドリンクを出す。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'manual', 'manual-evening', '夜：交流と見送り', '弁当配達、火打石のお見送り、翌朝の案内。到着済みのゲストから順に。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'manual', 'manual-foreign', '外国人ゲスト対応', '英語の基本セットで対応。込み入った会話は受付iPadの翻訳アプリ。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'manual', 'manual-family', 'ファミリー対応', '夏の川遊びは安全な浅瀬を案内。増水時は中止を促す。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'manual', 'manual-workation', 'ワーケーション対応', 'オフシーズンの長期滞在。Wi-Fi と静かな作業環境を案内。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'procedure', 'proc-checkin', 'チェックイン手順', '名前確認 → パスポート確認（法定）→ 用紙記入 → ベッド案内 → 館内案内 → ウェルカムドリンク。', 'midday_prep', null, '{}', 'ready', now()),
  (gen_random_uuid(), 'procedure', 'proc-welcome-drink', 'ウェルカムドリンクの一言', '「梅ジュースとみかんをどうぞ。地元のものです。」到着のねぎらいとともに出す。', 'midday_prep', null, '{}', 'ready', now()),
  (gen_random_uuid(), 'procedure', 'proc-shower', 'シャワー案内', 'シャワー・トイレの場所と使い方、タオルの位置を案内する。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'procedure', 'proc-kamidana', '神棚の作法', '二礼・二拍手・一礼。翌朝、希望者がご自分の手で安全祈願をできる。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'procedure', 'proc-hiuchi', '火打石（切り火）の進行', '出かける人の背後で火打石と火打金を打ち合わせ火花を散らし、安全を願う。固有の石・道具・保管場所・声かけ・辞退時対応はモーリーと実演して確定。', 'evening_close', null, '{}', 'needs_input', now()),
  (gen_random_uuid(), 'procedure', 'proc-payment', '決済の使い方（Square / PayPay）', '館内販売の決済手順。具体操作は要確認。', null, null, '{}', 'needs_input', now()),
  (gen_random_uuid(), 'procedure', 'proc-bento', '弁当の受け取り・見分け', '肉のおくだの弁当。ベジタリアンは緑シール。受け取り方法・見分けは要確認。', null, null, '{}', 'needs_input', now()),
  (gen_random_uuid(), 'procedure', 'proc-bbq', 'BBQ の運用', '火気の扱い、片付け、火の始末。固有の運用は要確認。', null, null, '{}', 'needs_input', now()),
  (gen_random_uuid(), 'procedure', 'proc-claim', 'クレーム対応', 'まず傾聴し謝意を示す。その場で判断せず運営に確認・連絡。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'procedure', 'proc-emergency', '緊急時手順', '緊急は電話。警察110／消防・救急119。重症は119。運営（肉のおくだ）080-8032-9762。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'area', 'area-trails', '熊野古道（小雲取越・大雲取越）', '小雲取越：小口→請川/本宮 約13km・約4時間30分。大雲取越：那智大社→小口 約14.5km・中辺路最難関。古道上に売店・自販機なし。昼食・水は出発前に用意。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'area', 'area-bus', '交通（バス）', 'JR新宮駅 ⇄ 小口は神丸（または志古）で乗り換え。便数は少ない。最新の時刻表は要確認、受付に紙を常備。', null, null, '{}', 'needs_input', now()),
  (gen_random_uuid(), 'area', 'area-taxi', 'タクシー', '新宮市内のタクシー手配（距離が長く高額）。事業者名・概算料金は要確認。', null, null, '{}', 'needs_input', now()),
  (gen_random_uuid(), 'area', 'area-shop', '買い物・売店', '小口にコンビニ・スーパーなし。最寄りは新宮方面で約1時間。直近店舗と距離は要確認。', null, null, '{}', 'needs_input', now()),
  (gen_random_uuid(), 'area', 'area-river', '川遊び（夏）', '赤木川・小口川は清流。安全な浅瀬・更衣/トイレの場所は現地確認。増水時は中止。', null, null, '{}', 'needs_input', now()),
  (gen_random_uuid(), 'emergency', 'emergency-contacts', '緊急連絡先', '警察 110 ／ 消防・救急 119 ／ 運営（肉のおくだ）080-8032-9762。緊急は電話。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'emergency', 'emergency-hospital', '医療機関', '救急・入院は新宮市立医療センター 0735-31-3333。日中の軽症は熊野川診療所（住所・電話・診療時間は要確認）。', null, null, '{}', 'needs_input', now()),
  (gen_random_uuid(), 'emergency', 'emergency-disaster', '想定災害', '主リスクは熊野川・赤木川の河川氾濫と土砂災害。大雨・台風時は警報を待たず早めの自主避難を。', null, null, '{}', 'ready', now()),
  (gen_random_uuid(), 'emergency', 'emergency-shelter', '避難場所', '小口自然の家（熊野川町上長井398、0735-45-2434）が現実的な拠点。小和瀬・小口地区の正式な指定避難場所は要確認。', null, null, '{}', 'needs_input', now()),
  (gen_random_uuid(), 'emergency', 'emergency-aed', 'AED', '最寄りのAED設置場所は要確認（小口自然の家・公民館等）。', null, null, '{}', 'needs_input', now()),
  (gen_random_uuid(), 'emergency', 'emergency-roster', '法定名簿の保管', '宿泊者名簿の保管場所は未定。保管場所・保存期間・施錠を決めて追記する。', null, null, '{}', 'needs_input', now()),
